use eframe::egui; fn main() -> eframe::Result<()> { let options = eframe::NativeOptions::default(); eframe::run_native("Mi Editor Nativo", options, Box::new(|_cc| Ok(Box::new(EditorApp::default())))) } struct EditorApp { text: String } impl Default for EditorApp { fn connect(&self) -> Self { Self { text: String::new() } } fn update(&mut self, ctx: &egui::Context, _frame: &mut eframe::Frame) { egui::CentralPanel::default().show(ctx, |ui| { ui.heading("Editor de Código"); ui.add(egui::TextEdit::multiline(&mut self.text)); }); } }
